changeSet.sql:
UPDATE damage_type SET code = upper(slug) WHERE code IS NULL;
INSERT INTO damage_type (damage_type_id, slug, code, name_ru, name_en) SELECT gen_random_uuid(), v.slug, v.code, v.name_ru, v.name_en FROM (VALUES ('slashing','SLASHING','Рубящий','Slashing'), ('piercing','PIERCING','Колющий','Piercing'), ('bludgeoning','BLUDGEONING','Дробящий','Bludgeoning'), ('fire','FIRE','Огонь','Fire'), ('cold','COLD','Холод','Cold'), ('lightning','LIGHTNING','Электричество','Lightning'), ('poison','POISON','Яд','Poison'), ('necrotic','NECROTIC','Некротический','Necrotic'), ('radiant','RADIANT','Излучение','Radiant'), ('psychic','PSYCHIC','Психический','Psychic'), ('force','FORCE','Силовое поле','Force'), ('thunder','THUNDER','Звук','Thunder'), ('acid','ACID','Кислота','Acid') ) AS v(slug, code, name_ru, name_en) WHERE NOT EXISTS ( SELECT 1 FROM damage_type d WHERE d.slug = v.slug AND d.homebrew_id IS NULL );
CREATE UNIQUE INDEX IF NOT EXISTS uq_damage_type_slug_system ON damage_type(slug) WHERE homebrew_id IS NULL;

ALTER TABLE enchantment_types DROP CONSTRAINT enchantment_types_damage_type_id_fkey;
ALTER TABLE item_templates DROP CONSTRAINT item_templates_damage_type_id_fkey;
ALTER TABLE item_types DROP CONSTRAINT item_types_damage_type_id_fkey;
ALTER TABLE skills DROP CONSTRAINT skills_damage_type_id_fkey;

UPDATE enchantment_types t SET damage_type_id = dt.damage_type_id
    FROM damage_type dt JOIN damage_types old ON lower(old.code) = dt.slug
    WHERE old.id = t.damage_type_id AND t.damage_type_id IS NOT NULL;
UPDATE item_templates t SET damage_type_id = dt.damage_type_id
    FROM damage_type dt JOIN damage_types old ON lower(old.code) = dt.slug
    WHERE old.id = t.damage_type_id AND t.damage_type_id IS NOT NULL;
UPDATE item_types t SET damage_type_id = dt.damage_type_id
    FROM damage_type dt JOIN damage_types old ON lower(old.code) = dt.slug
    WHERE old.id = t.damage_type_id AND t.damage_type_id IS NOT NULL;
UPDATE skills t SET damage_type_id = dt.damage_type_id
    FROM damage_type dt JOIN damage_types old ON lower(old.code) = dt.slug
    WHERE old.id = t.damage_type_id AND t.damage_type_id IS NOT NULL;

UPDATE enchantment_types SET damage_type_id = NULL WHERE damage_type_id IS NOT NULL
    AND damage_type_id NOT IN (SELECT damage_type_id FROM damage_type);
UPDATE item_templates SET damage_type_id = NULL WHERE damage_type_id IS NOT NULL
    AND damage_type_id NOT IN (SELECT damage_type_id FROM damage_type);
UPDATE item_types SET damage_type_id = NULL WHERE damage_type_id IS NOT NULL
    AND damage_type_id NOT IN (SELECT damage_type_id FROM damage_type);
UPDATE skills SET damage_type_id = NULL WHERE damage_type_id IS NOT NULL
    AND damage_type_id NOT IN (SELECT damage_type_id FROM damage_type);

ALTER TABLE enchantment_types ADD CONSTRAINT enchantment_types_damage_type_id_fkey
    FOREIGN KEY (damage_type_id) REFERENCES damage_type(damage_type_id);
ALTER TABLE item_templates ADD CONSTRAINT item_templates_damage_type_id_fkey
    FOREIGN KEY (damage_type_id) REFERENCES damage_type(damage_type_id);
ALTER TABLE item_types ADD CONSTRAINT item_types_damage_type_id_fkey
    FOREIGN KEY (damage_type_id) REFERENCES damage_type(damage_type_id);
ALTER TABLE skills ADD CONSTRAINT skills_damage_type_id_fkey
    FOREIGN KEY (damage_type_id) REFERENCES damage_type(damage_type_id);

ALTER TABLE monster_damage_resistances DROP CONSTRAINT monster_damage_resistances_damage_type_id_fkey;
ALTER TABLE monster_damage_immunities DROP CONSTRAINT monster_damage_immunities_damage_type_id_fkey;
ALTER TABLE monster_damage_vulnerabilities DROP CONSTRAINT monster_damage_vulnerabilities_damage_type_id_fkey;
ALTER TABLE feature_damages DROP CONSTRAINT feature_damages_damage_type_id_fkey;

UPDATE monster_damage_resistances t SET damage_type_id = dt.damage_type_id
    FROM damage_type dt JOIN bestiary_damage_types b ON lower(b.code) = dt.slug
    WHERE b.id = t.damage_type_id AND t.damage_type_id IS NOT NULL;
UPDATE monster_damage_immunities t SET damage_type_id = dt.damage_type_id
    FROM damage_type dt JOIN bestiary_damage_types b ON lower(b.code) = dt.slug
    WHERE b.id = t.damage_type_id AND t.damage_type_id IS NOT NULL;
UPDATE monster_damage_vulnerabilities t SET damage_type_id = dt.damage_type_id
