    WHERE b.id = t.damage_type_id AND t.damage_type_id IS NOT NULL;
UPDATE feature_damages t SET damage_type_id = dt.damage_type_id
    FROM damage_type dt JOIN bestiary_damage_types b ON lower(b.code) = dt.slug
    WHERE b.id = t.damage_type_id AND t.damage_type_id IS NOT NULL;

UPDATE monster_damage_resistances SET damage_type_id = NULL WHERE damage_type_id IS NOT NULL
    AND damage_type_id NOT IN (SELECT damage_type_id FROM damage_type);
UPDATE monster_damage_immunities SET damage_type_id = NULL WHERE damage_type_id IS NOT NULL
    AND damage_type_id NOT IN (SELECT damage_type_id FROM damage_type);
UPDATE monster_damage_vulnerabilities SET damage_type_id = NULL WHERE damage_type_id IS NOT NULL
    AND damage_type_id NOT IN (SELECT damage_type_id FROM damage_type);
UPDATE feature_damages SET damage_type_id = NULL WHERE damage_type_id IS NOT NULL
    AND damage_type_id NOT IN (SELECT damage_type_id FROM damage_type);

ALTER TABLE monster_damage_resistances ADD CONSTRAINT monster_damage_resistances_damage_type_id_fkey
    FOREIGN KEY (damage_type_id) REFERENCES damage_type(damage_type_id);
ALTER TABLE monster_damage_immunities ADD CONSTRAINT monster_damage_immunities_damage_type_id_fkey
    FOREIGN KEY (damage_type_id) REFERENCES damage_type(damage_type_id);
ALTER TABLE monster_damage_vulnerabilities ADD CONSTRAINT monster_damage_vulnerabilities_damage_type_id_fkey
    FOREIGN KEY (damage_type_id) REFERENCES damage_type(damage_type_id);
